12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_RATE = 0.1;
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	
26	// Item-specific surcharges, each a rate applied additively to the base premium
27	// when its condition holds. First insurance always applies; the rest are
28	// conditional on the item.
29	const mainItemSurchargeRates = (item: Item): number[] => [
30	  FIRST_INSURANCE_RATE,
31	  ...(item.cursed ? [CURSE_SURCHARGE_RATE] : []),
32	  ...((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
33	    ? [HIGH_ENCHANTMENT_RATE]
34	    : []),
35	];
36	
37	// A main item's premium: its base premium scaled by 1 plus the sum of all
38	// applicable surcharge rates.
39	const mainItemPremium = (item: Item): number => {
40	  const base = BASE_PREMIUMS[item.type];
41	  const totalRate = mainItemSurchargeRates(item).reduce(
42	    (sum, rate) => sum + rate,
43	    0,
44	  );
45	  return base * (1 + totalRate);
46	};
47	
48	const COMPONENT_TYPES = ["rune", "moonstone"];
49	const COMPONENT_BASE_PREMIUM = 25;
50	const COMPONENT_BLOCK_SIZE = 3;
51	const COMPONENT_BLOCK_PREMIUM = 60;
52	
53	const isComponent = (item: Item): boolean =>
54	  COMPONENT_TYPES.includes(item.type);
55	
56	// Base premium for `count` alike components: a block premium applies only for
57	// exactly one block's worth (3) of components; otherwise each is priced individually.
58	const componentBasePremium = (count: number): number => {
59	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
60	  return count * COMPONENT_BASE_PREMIUM;
61	};
62	
63	const countByType = (items: Item[]): Map<string, number> => {
64	  const counts = new Map<string, number>();
65	  for (const item of items) {
66	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
67	  }
68	  return counts;
69	};
70	
71	// The block rule is per-type ("alike" = same type), so price each type's count
72	// independently and sum across types.
73	const componentItemsBase = (componentItems: Item[]): number =>
74	  [...countByType(componentItems).values()].reduce(
75	    (base, count) => base + withFirstInsurance(componentBasePremium(count)),
76	    0,
77	  );
78	
79	// Every item is treated as first insurance today, so the surcharge is applied
80	// uniformly to each base premium, using the same additive rate as main items
81	// (single source of truth for first insurance).
82	const withFirstInsurance = (basePremium: number): number =>
83	  basePremium * (1 + FIRST_INSURANCE_RATE);
84	
85	// Round up in MHPCO's favour, guarding against floating-point noise
86	// (e.g. 197.50000000001 should still round to 198, not 199).
87	const roundUpInMHPCOFavor = (amount: number): number =>
88	  Math.ceil(Number(amount.toFixed(6)));
89	
90	export const quote = (
91	  items: Item[],
92	  customer: Customer,
93	  contractIndex: number,
94	): number => {
95	  const mainItems = items.filter((item) => !isComponent(item));
96	  const componentItems = items.filter((item) => isComponent(item));
97	
98	  const mainBase = mainItems.reduce(
99	    (sum, item) => sum + mainItemPremium(item),
100	    0,
101	  );
102	  const componentBase = componentItemsBase(componentItems);
103	
104	  return roundUpInMHPCOFavor(mainBase + componentBase + PROCESSING_FEE);
105	};
